#!/usr/bin/env node
// gate-generated-artifacts-source-only — the generated-artifacts-current gate's
// consumer-install guard (v1.73.1).
//
// The generator discipline (authored sources -> `template/maddu/**` targets,
// regenerated by `scripts/generate.mjs`) ships only in a Máddu SOURCE checkout.
// A consumer install carries none of it, so the gate must SKIP there — keyed on
// the positive presence of `scripts/generate.mjs` (the remediation script the
// gate's own message points at), not on per-target file absence. The old
// absence-inference FAILed on a real consumer install when a stray
// `template/maddu/` tree leaked into the repo root (npx clone / fork), telling
// the operator to run a script that wasn't there. This fixture locks the guard:
// no generate script -> skip; generate script present -> proceed past the guard.
//
// Exit codes: 0 = OK, 1 = assertion failed, 2 = harness error.

import { mkdtemp, mkdir, writeFile, rm } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import gate from '../../template/maddu/runtime/gates/builtin/generated-artifacts-current.mjs';

let passed = 0, failed = 0;
function ok(name, cond, extra = '') {
  console.log(`  ${cond ? '[PASS]' : '[FAIL]'} ${name}${extra ? ` - ${extra}` : ''}`);
  if (cond) passed++; else failed++;
}

async function main() {
  ok('gate has the expected id + safety severity', gate.id === 'generated-artifacts-current' && gate.severity === 'safety');

  // ── Consumer install: no scripts/generate.mjs, even with a leaked stale
  //    framework-source tree present (the exact shape that FAILed in the field). ──
  const consumer = await mkdtemp(join(tmpdir(), 'maddu-gen-consumer-'));
  await mkdir(join(consumer, 'template', 'maddu', 'agent-files'), { recursive: true });
  await writeFile(join(consumer, 'template', 'maddu', 'agent-files', 'rules.json'), '{}');
  await writeFile(
    join(consumer, 'template', 'maddu', 'CLAUDE.md'),
    '<!-- GENERATED:hard-rules -->\nSTALE\n<!-- /GENERATED:hard-rules -->\n',
  );
  const rc = await gate.run({ repoRoot: consumer });
  ok('consumer install (no generate.mjs) skips clean', rc.ok === true && /consumer install/.test(rc.message), rc.message);

  // ── Source checkout signal present: the guard must NOT short-circuit. With no
  //    resolvable generation engine in a bare temp repo, the gate falls through
  //    to its own "engine not present" skip — proving it got past the guard. ──
  const source = await mkdtemp(join(tmpdir(), 'maddu-gen-source-'));
  await mkdir(join(source, 'scripts'), { recursive: true });
  await writeFile(join(source, 'scripts', 'generate.mjs'), '// dev wrapper\n');
  const rs = await gate.run({ repoRoot: source });
  ok('generate.mjs present -> guard does not short-circuit', !/consumer install/.test(rs.message), rs.message);

  await rm(consumer, { recursive: true, force: true });
  await rm(source, { recursive: true, force: true });
}

try {
  await main();
  console.log('');
  console.log(`gate-generated-artifacts-source-only: ${passed} pass - ${failed} fail`);
  if (failed > 0) process.exit(1);
  console.log('gate-generated-artifacts-source-only OK');
  process.exit(0);
} catch (err) {
  console.error(`harness error: ${err.stack || err.message}`);
  process.exit(2);
}
